import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.stream.ActorMaterializer
import scala.concurrent.ExecutionContext
import scala.concurrent.Future
import scala.concurrent.duration._
import scala.util.{Failure, Success}

object WebhookProxyService extends App {

  implicit val system: ActorSystem = ActorSystem("WebhookProxyService")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext: ExecutionContext = system.dispatcher

  val route =
    path("proxy") {
      post {
        entity(as[String]) { userUrl =>
          // Basic validation for URL format, can be extended
          if (userUrl.startsWith("http://") || userUrl.startsWith("https://")) {
            val requestFuture: Future[HttpResponse] =
              Http().singleRequest(HttpRequest(uri = userUrl))

            onComplete(requestFuture) {
              case Success(response) =>
                // Consume the entity from the target service response
                response.entity.toStrict(10.seconds).flatMap { strictEntity =>
                  Future.successful(
                    complete(
                      HttpResponse(
                        status = response.status,
                        headers = response.headers,
                        entity = strictEntity.data.utf8String
                      )
                    )
                  )
                }.recover {
                  case ex =>
                    system.log.error(s"Failed to process entity from target URL $userUrl: ${ex.getMessage}")
                    complete(StatusCodes.InternalServerError, s"Failed to process target response: ${ex.getMessage}")
                }

              case Failure(ex) =>
                system.log.error(s"Request to $userUrl failed: ${ex.getMessage}")
                complete(StatusCodes.BadGateway, s"Failed to fetch content from $userUrl: ${ex.getMessage}")
            }
          } else {
            complete(StatusCodes.BadRequest, "Invalid URL format. URL must start with http:// or https://")
          }
        }
      }
    }

  val bindingFuture = Http().bindAndHandle(route, "0.0.0.0", 8080)

  println(s"Server online at http://0.0.0.0:8080/\nPress RETURN to stop...")

  sys.addShutdownHook {
    bindingFuture
      .flatMap(_.unbind()) // trigger unbinding from the port
      .onComplete(_ => system.terminate()) // and shutdown when done
  }
}